define(["jquery","core/ajax","mod_gestionprojet/cdcf","mod_gestionprojet/autosave"],function($,Ajax,Cdcf,Autosave){"use strict";function bootProvidedReadOnly(){var providedRoot=document.getElementById("cdcfProvidedRoot");if(!providedRoot){return}var raw=providedRoot.getAttribute("data-cdcf");if(!raw){return}var data;try{data=JSON.parse(raw)}catch(e){return}Cdcf.init({container:providedRoot,initialData:data,lang:window._gpCdcfLang||{},projetNom:providedRoot.getAttribute("data-projet")||"",isLocked:true,onChange:function(){}})}function init(cfg){window._gpCdcfLang=cfg.lang;bootProvidedReadOnly();var dataField=document.getElementById("cdcfDataField");var root=document.getElementById("cdcfRoot");if(!root||!dataField){return}Cdcf.init({container:root,initialData:cfg.initial,lang:cfg.lang,projetNom:cfg.projetNom,isLocked:cfg.isLocked,onChange:function(data){dataField.value=JSON.stringify(data)}});$("#revertButton").on("click",function(){if(!window.confirm(cfg.confirmRevert)){return}Ajax.call([{methodname:"mod_gestionprojet_submit_step",args:{cmid:cfg.cmid,step:cfg.step,action:"revert"}}])[0].done(function(d){if(d.success){window.location.reload()}})});if(!cfg.isLocked){Autosave.init({cmid:cfg.cmid,step:cfg.step,groupid:cfg.groupid,mode:cfg.mode||undefined,interval:cfg.autosaveMs,formSelector:"#cdcfForm",serialize:function(){var payload={interacteurs_data:dataField.value};var aiTextarea=document.getElementById("ai_instructions");if(aiTextarea){payload.ai_instructions=aiTextarea.value}var subDate=document.getElementById("submission_date");if(subDate){payload.submission_date=subDate.value}var deadDate=document.getElementById("deadline_date");if(deadDate){payload.deadline_date=deadDate.value}return payload}});var $saveBtn=$("#saveButton");if($saveBtn.length&&cfg.redirectAfterSave){$saveBtn.on("click",function(){var prev=Autosave.onSave;Autosave.onSave=function(response){if(prev){prev(response)}window.setTimeout(function(){window.location.href=cfg.redirectAfterSave},800)};Autosave.save()})}}}return{init:init}});